#!/usr/bin/env bash
# Mycelium reproducible toolchain distribution — pinned, content-addressed install (M-734; E16-1).
#
# Installs a toolchain *artifact directory* by VERIFYING it against a committed content-address pin
# before copying it into place. Re-running on the same pinned artifact produces a byte-identical
# install; any divergence between the artifact and the pin is a NEVER-SILENT error (G2). The pin is
# a self-describing content address (`<algo>:<hex>`), so the integrity check is honest about which
# hash backs it (ADR-003: blake3 preferred; sha256 fallback when b3sum is unavailable).
#
#   install.sh --artifact <dir> --prefix <dest> [--pins <file>]   # verify <dir> vs pins, then install
#   install.sh --artifact <dir> --verify-only   [--pins <file>]   # verify only (no copy)
#   install.sh --artifact <dir> --update-pins   [--pins <file>]   # (re)compute + write the pin file
#
# Honesty / scope (VR-5): this ships the pin/verify/install MECHANISM and is fully reproducible for
# any artifact directory. Pinning the actual released compiler binaries additionally requires a
# reproducible release BUILD (so two machines produce byte-identical binaries) — that build is
# deferred; this script does not pretend the binaries are already reproducible, it makes the
# install of a GIVEN artifact reproducible and verifiable.
#
# STRICT, never skip-graceful (M-734 DoD): if no supported hasher is present, this HARD-FAILS with
# instructions — it does not silently skip the integrity check.
#
# Exit codes: 0 ok · 5 integrity mismatch · 64 usage · 66 I/O · 69 no hasher available.
set -euo pipefail

DEFAULT_PINS="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)/pins"

die() { echo "dist: error: $*" >&2; exit "${2:-1}"; }

# Pick the content-address algorithm: blake3 (ADR-003) if b3sum is present, else sha256. If NEITHER
# is available the integrity check cannot run — hard-fail, never skip (M-734 DoD).
detect_algo() {
  if command -v b3sum >/dev/null 2>&1; then echo blake3
  elif command -v sha256sum >/dev/null 2>&1; then echo sha256
  else die "no content-address hasher found (install b3sum for blake3, or sha256sum) — refusing to install without an integrity check" 69
  fi
}

# hash_file <algo> <path> -> "<algo>:<hex>"
hash_file() {
  local algo=$1 path=$2 hex
  case "$algo" in
    blake3) hex=$(b3sum --no-names "$path" | awk '{print $1}') ;;
    sha256) hex=$(sha256sum "$path" | awk '{print $1}') ;;
    *) die "unknown hash algorithm: $algo" ;;
  esac
  printf '%s:%s' "$algo" "$hex"
}

# Emit the canonical per-file manifest for <dir> (sorted "relpath<TAB><algo>:<hex>" lines) to stdout.
artifact_manifest() {
  local algo=$1 dir=$2 rel
  ( cd "$dir" && find . -type f | LC_ALL=C sort ) | while IFS= read -r rel; do
    rel=${rel#./}
    printf '%s\t%s\n' "$rel" "$(hash_file "$algo" "$dir/$rel")"
  done
}

# The artifact ROOT content address: the hash of the canonical manifest text (a Merkle-style root,
# mirroring the spore content_address; ADR-003). Deterministic for identical contents.
artifact_root() {
  local algo=$1 dir=$2 tmp
  tmp=$(mktemp)
  artifact_manifest "$algo" "$dir" > "$tmp"
  local roothex
  case "$algo" in
    blake3) roothex=$(b3sum --no-names "$tmp" | awk '{print $1}') ;;
    sha256) roothex=$(sha256sum "$tmp" | awk '{print $1}') ;;
  esac
  rm -f "$tmp"
  printf '%s:%s' "$algo" "$roothex"
}

write_pins() {
  local algo=$1 dir=$2 pins=$3
  {
    echo "# Mycelium toolchain distribution pin (M-734). GENERATED by scripts/dist/install.sh --update-pins."
    echo "# A self-describing content address (<algo>:<hex>) over the artifact directory. Do not hand-edit."
    echo "algo $algo"
    echo "artifact $(artifact_root "$algo" "$dir")"
    artifact_manifest "$algo" "$dir" | while IFS=$'\t' read -r rel h; do
      echo "file $rel $h"
    done
  } > "$pins"
  echo "dist: wrote pin file $pins ($(grep -c '^file ' "$pins") file(s), algo $algo)"
}

verify() {
  local dir=$1 pins=$2
  [[ -f "$pins" ]] || die "pin file not found: $pins (run with --update-pins to create it)" 66
  local pin_algo pin_root
  pin_algo=$(awk '$1=="algo"{print $2}' "$pins")
  pin_root=$(awk '$1=="artifact"{print $2}' "$pins")
  [[ -n "$pin_algo" && -n "$pin_root" ]] || die "malformed pin file $pins (missing algo/artifact)" 66
  # The pin demands a specific algorithm; the matching hasher MUST be present (never skip).
  case "$pin_algo" in
    blake3) command -v b3sum    >/dev/null 2>&1 || die "pin requires blake3 but b3sum is not installed" 69 ;;
    sha256) command -v sha256sum >/dev/null 2>&1 || die "pin requires sha256 but sha256sum is not installed" 69 ;;
    *) die "pin file names an unknown algorithm: $pin_algo" 66 ;;
  esac

  # Per-file verification: every pinned file must exist and match (a missing/extra/mutated file is
  # a never-silent mismatch).
  local fail=0 rel want got
  while read -r kw rel want; do
    [[ "$kw" == "file" ]] || continue
    if [[ ! -f "$dir/$rel" ]]; then
      echo "dist: MISSING $rel (pinned but not in artifact)" >&2; fail=1; continue
    fi
    got=$(hash_file "$pin_algo" "$dir/$rel")
    if [[ "$got" != "$want" ]]; then
      echo "dist: MISMATCH $rel" >&2
      echo "        pinned: $want" >&2
      echo "        actual: $got"  >&2
      fail=1
    fi
  done < "$pins"

  # Root verification: the artifact root must equal the pinned root (catches added files too).
  local root
  root=$(artifact_root "$pin_algo" "$dir")
  if [[ "$root" != "$pin_root" ]]; then
    echo "dist: ROOT MISMATCH" >&2
    echo "        pinned: $pin_root" >&2
    echo "        actual: $root"     >&2
    fail=1
  fi

  (( fail == 0 )) || die "artifact does not match its pin — refusing to install a non-reproducible/tampered toolchain (G2)" 5
  echo "dist: verified — artifact matches pin ($pin_root)"
}

install_to() {
  local dir=$1 prefix=$2
  mkdir -p "$prefix" || die "cannot create prefix $prefix" 66
  # A verified copy: deterministic, byte-for-byte (re-running yields an identical tree).
  ( cd "$dir" && find . -type f | LC_ALL=C sort ) | while IFS= read -r rel; do
    rel=${rel#./}
    mkdir -p "$prefix/$(dirname "$rel")"
    cp -p "$dir/$rel" "$prefix/$rel"
  done
  echo "dist: installed -> $prefix"
}

main() {
  local artifact="" prefix="" pins="$DEFAULT_PINS" mode="install"
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --artifact) artifact=${2:?--artifact needs a dir}; shift 2 ;;
      --prefix)   prefix=${2:?--prefix needs a dir};     shift 2 ;;
      --pins)     pins=${2:?--pins needs a file};        shift 2 ;;
      --verify-only) mode="verify";     shift ;;
      --update-pins) mode="update";     shift ;;
      -h|--help) grep '^#' "${BASH_SOURCE[0]}" | sed 's/^# \{0,1\}//'; exit 0 ;;
      *) die "unknown argument: $1" 64 ;;
    esac
  done
  [[ -n "$artifact" ]] || die "missing --artifact <dir>" 64
  [[ -d "$artifact" ]] || die "artifact directory not found: $artifact" 66

  local algo; algo=$(detect_algo)
  case "$mode" in
    update) write_pins "$algo" "$artifact" "$pins" ;;
    verify) verify "$artifact" "$pins" ;;
    install)
      [[ -n "$prefix" ]] || die "missing --prefix <dest> for install (or use --verify-only)" 64
      verify "$artifact" "$pins"
      install_to "$artifact" "$prefix"
      ;;
  esac
}

main "$@"
